tiles.chartQuery:
WITH roots AS ( SELECT span_trace_id, span_span_id, span_start_time_unix_nano, span_duration_ns, span_status_code, "gen_ai.request.model" AS model FROM $trace_dataset WHERE "gen_ai.operation.name" = 'invoke_agent'
), trace_stats AS ( SELECT span_trace_id, COUNT(*) FILTER (WHERE "gen_ai.operation.name" = 'chat') AS chat_calls, COUNT(*) FILTER (WHERE COALESCE("gen_ai.tool.name", "tool.name") IS NOT NULL OR "gen_ai.operation.name" = 'execute_tool') AS tool_calls FROM $trace_dataset GROUP BY span_trace_id
), trace_cost AS ( SELECT span_trace_id, ROUND(SUM(agent_cost("gen_ai.provider.name", COALESCE("gen_ai.request.model", "gen_ai.response.model"), CAST("gen_ai.usage.input_tokens" AS DOUBLE), CAST("gen_ai.usage.output_tokens" AS DOUBLE), p_timestamp)), 6) AS cost_usd, SUM(CAST("gen_ai.usage.input_tokens" AS DOUBLE)) AS total_input_tokens, SUM(CAST("gen_ai.usage.output_tokens" AS DOUBLE)) AS total_output_tokens FROM $trace_dataset WHERE COALESCE("gen_ai.request.model", "gen_ai.response.model") IS NOT NULL AND "gen_ai.usage.input_tokens" IS NOT NULL AND "gen_ai.usage.output_tokens" IS NOT NULL GROUP BY span_trace_id
)
SELECT r.span_start_time_unix_nano AS start_time, r.span_trace_id, r.model, ROUND(r.span_duration_ns / 1000000000.0, 2) AS duration_s, CASE WHEN r.span_status_code = 2 THEN true ELSE false END AS errored, COALESCE(ts.chat_calls, 0) AS chat_calls, COALESCE(ts.tool_calls, 0) AS tool_calls, tc.cost_usd, tc.total_input_tokens, tc.total_output_tokens
FROM roots r
LEFT JOIN trace_stats ts ON r.span_trace_id = ts.span_trace_id
LEFT JOIN trace_cost tc ON tc.span_trace_id = r.span_trace_id
ORDER BY r.span_duration_ns DESC
LIMIT 25

WITH roots AS ( SELECT span_trace_id, span_span_id, span_start_time_unix_nano, span_duration_ns, span_status_code, "gen_ai.request.model" AS model, "gen_ai.response.finish_reasons" AS finish_reasons FROM $trace_dataset WHERE "gen_ai.operation.name" = 'invoke_agent'
), trace_stats AS ( SELECT span_trace_id, COUNT(*) FILTER (WHERE "gen_ai.operation.name" = 'chat') AS chat_calls, COUNT(*) FILTER (WHERE COALESCE("gen_ai.tool.name", "tool.name") IS NOT NULL OR "gen_ai.operation.name" = 'execute_tool') AS tool_calls FROM $trace_dataset GROUP BY span_trace_id
), trace_cost AS ( SELECT span_trace_id, ROUND(SUM(agent_cost("gen_ai.provider.name", COALESCE("gen_ai.request.model", "gen_ai.response.model"), CAST("gen_ai.usage.input_tokens" AS DOUBLE), CAST("gen_ai.usage.output_tokens" AS DOUBLE), p_timestamp)), 6) AS cost_usd, SUM(CAST("gen_ai.usage.input_tokens" AS DOUBLE)) AS total_input_tokens, SUM(CAST("gen_ai.usage.output_tokens" AS DOUBLE)) AS total_output_tokens FROM $trace_dataset WHERE COALESCE("gen_ai.request.model", "gen_ai.response.model") IS NOT NULL AND "gen_ai.usage.input_tokens" IS NOT NULL AND "gen_ai.usage.output_tokens" IS NOT NULL GROUP BY span_trace_id
)
SELECT r.span_start_time_unix_nano AS start_time, r.span_trace_id, r.model, ROUND(r.span_duration_ns / 1000000000.0, 2) AS duration_s, CASE WHEN r.span_status_code = 2 THEN true ELSE false END AS errored, COALESCE(ts.chat_calls, 0) AS chat_calls, COALESCE(ts.tool_calls, 0) AS tool_calls, r.finish_reasons, tc.cost_usd, tc.total_input_tokens, tc.total_output_tokens
FROM roots r
LEFT JOIN trace_stats ts ON r.span_trace_id = ts.span_trace_id
LEFT JOIN trace_cost tc ON tc.span_trace_id = r.span_trace_id
ORDER BY r.span_start_time_unix_nano DESC
LIMIT 50

WITH roots AS ( SELECT span_trace_id, MIN(p_timestamp) AS start_time, MAX(span_status_code) AS status_code, ROUND(MAX(span_duration_ns) / 1000000000.0, 3) AS latency_s FROM $trace_dataset WHERE "gen_ai.operation.name" = 'invoke_agent' GROUP BY span_trace_id
), chats AS ( SELECT span_trace_id, COUNT(*) AS chat_calls, SUM(CAST("gen_ai.usage.input_tokens" AS DOUBLE) + CAST("gen_ai.usage.output_tokens" AS DOUBLE)) AS total_tokens, ROUND(SUM(agent_cost("gen_ai.provider.name", COALESCE("gen_ai.request.model", "gen_ai.response.model"), CAST("gen_ai.usage.input_tokens" AS DOUBLE), CAST("gen_ai.usage.output_tokens" AS DOUBLE), p_timestamp)), 6) AS cost_usd FROM $trace_dataset WHERE "gen_ai.operation.name" = 'chat' AND COALESCE("gen_ai.request.model", "gen_ai.response.model") IS NOT NULL AND "gen_ai.usage.input_tokens" IS NOT NULL AND "gen_ai.usage.output_tokens" IS NOT NULL GROUP BY span_trace_id
), tools AS ( SELECT span_trace_id, COUNT(*) AS tool_calls FROM $trace_dataset WHERE "gen_ai.operation.name" = 'execute_tool' GROUP BY span_trace_id
)
SELECT r.start_time, r.span_trace_id, CASE WHEN r.status_code = 2 THEN 'error' ELSE 'ok' END AS status, r.latency_s, COALESCE(c.chat_calls, 0) AS chat_calls, COALESCE(t.tool_calls, 0) AS tool_calls, COALESCE(c.total_tokens, 0) AS total_tokens, c.cost_usd
FROM roots r
LEFT JOIN chats c ON r.span_trace_id = c.span_trace_id
LEFT JOIN tools t ON r.span_trace_id = t.span_trace_id
ORDER BY r.start_time DESC
LIMIT 50
